const payload = $json.body ?? $json;

const required = ['reportId', 'contentType', 'contentId', 'reason', 'severity'];
const missing = required.filter((field) => {
  const value = payload[field];
  return value === undefined || value === null || String(value).trim() === '';
});

if (missing.length > 0) {
  throw new Error(`Invalid moderation payload: missing ${missing.join(', ')}`);
}

const severity = String(payload.severity).toLowerCase().trim();
const allowed = ['low', 'medium', 'high', 'critical'];
if (!allowed.includes(severity)) {
  throw new Error(`Invalid severity: ${severity}. Allowed: ${allowed.join(', ')}`);
}

const correlationId = payload.correlationId && String(payload.correlationId).trim()
  ? String(payload.correlationId).trim()
  : `${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;

return [{
  json: {
    reportId: String(payload.reportId).trim(),
    contentType: String(payload.contentType).trim(),
    contentId: String(payload.contentId).trim(),
    reportedBy: payload.reportedBy ? String(payload.reportedBy).trim() : 'unknown',
    reason: String(payload.reason).trim(),
    severity,
    description: payload.description ? String(payload.description) : '',
    createdAt: payload.createdAt ? String(payload.createdAt) : new Date().toISOString(),
    correlationId,
    escalated: severity === 'high' || severity === 'critical',
    autoAction: severity === 'critical'
  }
}];
